package be.schaubroeck.lpb.rkm.rekenmotor.validators;

import be.schaubroeck.lpb.rkm.rekenmotor.service.ExtraSqlService.SimpelWeddebepaling;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.SchaalVersie;
import be.schaubroeck.lpb.tools.enumtypes.RekenControleCode;
import be.schaubroeck.lpb.tools.service.SchaalVersieService;
import lombok.AllArgsConstructor;
import org.apache.commons.lang.StringUtils;

@AllArgsConstructor
public class SchaalVersieValidator {

    private SchaalVersieService schaalVersieService;

    public void valideerVersieVanSchaal(Opdracht opdracht, SimpelWeddebepaling simpelWeddebepaling, RegulManager regulManager) {
        if (simpelWeddebepaling == null) {
            return;
        }
        if (!checkInternNrEnSchaalVersieBeideIngevuldofBeideLeeg(simpelWeddebepaling)) {
            regulManager.addProtoWaarschuwing(opdracht, RekenControleCode.VERSIENR_SCHAAL_ONTBREEKT, "Versie nummer voor schaal ontbreekt");
        } else if (checkCombinatieSchaalEnVersieBestaatNiet(simpelWeddebepaling)) {
            regulManager.addProtoWaarschuwing(opdracht, RekenControleCode.VERSIENR_SCHAAL_ONTBREEKT, "Combinatie internNr en versie bestaat niet");
        }
    }

    public boolean checkCombinatieSchaalEnVersieBestaatNiet(SimpelWeddebepaling simpelWeddebepaling) {
        if (!StringUtils.isBlank(simpelWeddebepaling.getInternNr())) {
            SchaalVersie schaalVersie = schaalVersieService.getByInternNrVersie(simpelWeddebepaling.getInternNr(), simpelWeddebepaling.getSchaalVersie());
            return schaalVersie == null;
        } else {
            return false;
        }

    }

    public boolean checkInternNrEnSchaalVersieBeideIngevuldofBeideLeeg(SimpelWeddebepaling simpelWeddebepaling) {
        boolean schaalVersieEmpty = simpelWeddebepaling.getSchaalVersie() == null || simpelWeddebepaling.getSchaalVersie() == 0;
        boolean internNrEmpty = StringUtils.isBlank(simpelWeddebepaling.getInternNr());
        return schaalVersieEmpty == internNrEmpty;
    }
}
